import os
import json
import logging
import boto3
from urllib.parse import unquote_plus

# Configure logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Initialize AWS clients
s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

# Environment variables (configure in Lambda console)
OUTPUT_BUCKET = os.environ.get('OUTPUT_BUCKET', 'your-default-output-bucket')
SNS_TOPIC_ARN = os.environ.get('SNS_TOPIC_ARN', 'arn:aws:sns:your-region:your-account-id:your-sns-topic-name')

def lambda_handler(event, context):
    """
    Processes S3 image upload events, reads the image, performs a dummy operation,
    writes results back to S3, and sends an SNS notification.
    """
    logger.info("Received event: %s", json.dumps(event))

    for record in event['Records']:
        if 's3' not in record:
            logger.warning("Record does not contain S3 event information. Skipping: %s", json.dumps(record))
            continue

        try:
            bucket_name = record['s3']['bucket']['name']
            # Object key might contain URL-encoded characters
            object_key = unquote_plus(record['s3']['object']['key'])
            file_size = record['s3']['object']['size']

            logger.info("Processing S3 object: s3://%s/%s (Size: %d bytes)", bucket_name, object_key, file_size)

            # 1. Read from S3
            try:
                response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
                image_content = response['Body'].read()
                content_type = response['ContentType']
                logger.info("Successfully read object '%s' from bucket '%s'. Content-Type: %s", object_key, bucket_name, content_type)
            except Exception as e:
                logger.error("Error reading object %s from bucket %s: %s", object_key, bucket_name, e)
                raise # Re-raise to halt processing for this record

            # 2. Perform dummy image processing (replace with actual logic)
            # For demonstration, we'll just create a simple text result.
            processed_data = f"Processed image: {object_key}\n" \
                             f"Original size: {len(image_content)} bytes\n" \
                             f"Simulated processing complete at: {context.aws_request_id}"
            result_key = f"processed/{object_key}.txt" # Example output key
            result_content_type = 'text/plain'

            logger.info("Dummy processing complete for %s. Result will be stored as %s", object_key, result_key)

            # 3. Write results back to S3
            try:
                s3_client.put_object(
                    Bucket=OUTPUT_BUCKET,
                    Key=result_key,
                    Body=processed_data.encode('utf-8'),
                    ContentType=result_content_type
                )
                logger.info("Successfully wrote processed data to s3://%s/%s", OUTPUT_BUCKET, result_key)
            except Exception as e:
                logger.error("Error writing processed data to s3://%s/%s: %s", OUTPUT_BUCKET, result_key, e)
                raise # Re-raise

            # 4. Send SNS notification
            notification_message = {
                "statusCode": 200,
                "inputObject": f"s3://{bucket_name}/{object_key}",
                "outputObject": f"s3://{OUTPUT_BUCKET}/{result_key}",
                "message": f"Image processing complete for {object_key}. Result available at s3://{OUTPUT_BUCKET}/{result_key}"
            }
            try:
                sns_client.publish(
                    TopicArn=SNS_TOPIC_ARN,
                    Message=json.dumps(notification_message),
                    Subject=f"Image Processed: {object_key}"
                )
                logger.info("Successfully published SNS notification for %s", object_key)
            except Exception as e:
                logger.error("Error publishing SNS notification for %s: %s", object_key, e)
                # Don't re-raise here, as the core processing and S3 write might have succeeded.
                # SNS notification is often a secondary concern.

        except Exception as e:
            logger.critical("Failed to process S3 record for object '%s'. Error: %s", object_key if 'object_key' in locals() else 'unknown', e, exc_info=True)
            # Depending on error handling strategy, you might want to return an error status
            # or use a Dead-Letter Queue for such failures.
            # For MVP, we log and continue to the next record if any.

    return {
        'statusCode': 200,
        'body': json.dumps('Image processing initiated successfully for all records.')
    }